SELECT COUNT(*) 
FROM research_teams 
WHERE team_id = 0;

SELECT site_name 
FROM sites 
WHERE latitude > (SELECT latitude FROM sites WHERE site_name = 'barr');

SELECT *
FROM users
WHERE user_id = (SELECT user_id FROM user_data_access WHERE data_id = 1);

SELECT method_name 
FROM collection_methods 
WHERE method_id = 0;
